#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <iostream>
#include <vector>
#include <algorithm>
#include <chrono>

#define CHECK_CUDA(call) do { \
    cudaError_t err = call; \
    if (err != cudaSuccess) { \
        fprintf(stderr, "CUDA error at %s:%d - %s\n", __FILE__, __LINE__, cudaGetErrorString(err)); \
        exit(1); \
    } \
} while(0)

__global__ void measure_kernel(unsigned long long* start_clock, unsigned long long* end_clock, float* dummy_output, int iterations) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Initialize clock readings
    if (idx == 0) {
        *start_clock = clock64();
    }

    // Perform compute-intensive work to maintain boost clock
    float val = threadIdx.x * blockIdx.x + 1.0f;
    for (int i = 0; i < iterations; ++i) {
        // Multiple FMA operations to ensure compute intensity
        val = fmaf(val, val, val);
        val = fmaf(val, 2.0f, 1.0f);
        val = fmaf(val, 0.5f, 3.0f);
        val = fmaf(val, val, 4.0f);
        val = fmaf(val, 0.25f, 5.0f);
    }

    if (idx == 0) {
        *end_clock = clock64();
    }

    // Store result to prevent optimization
    dummy_output[idx % 32] = val;
}

__global__ void warmup_kernel(int duration_ms) {
    unsigned long long start = clock64();
    unsigned long long freq_approx = 1500000; // Assume ~1.5 GHz as starting point
    unsigned long long target_cycles = (freq_approx * duration_ms) / 1000;

    float val = 1.0f;
    unsigned long long current = start;
    while ((current - start) < target_cycles) {
        val = fmaf(val, val, val);
        val = fmaf(val, 2.0f, 1.0f);
        val = fmaf(val, 0.5f, 3.0f);
        val = fmaf(val, val, 4.0f);
        current = clock64();
    }

    // Store result to prevent optimization
    if (threadIdx.x == 0 && blockIdx.x == 0) {
        printf("Warmup completed\n");
    }
}

int main() {
    // Warm up GPU to reach boost clock
    cudaSetDevice(0);
    int deviceId;
    CHECK_CUDA(cudaGetDevice(&deviceId));

    // Launch warmup kernel for 200ms
    warmup_kernel<<<1, 32>>>(200);
    CHECK_CUDA(cudaDeviceSynchronize());

    const int num_measurements = 11;
    std::vector<float> frequencies(num_measurements);

    // Allocate device memory for clock measurements
    unsigned long long *d_start_clock, *d_end_clock;
    float *d_dummy_output;
    CHECK_CUDA(cudaMalloc(&d_start_clock, sizeof(unsigned long long)));
    CHECK_CUDA(cudaMalloc(&d_end_clock, sizeof(unsigned long long)));
    CHECK_CUDA(cudaMalloc(&d_dummy_output, 32 * sizeof(float)));

    for (int i = 0; i < num_measurements; i++) {
        cudaEvent_t start_event, stop_event;
        CHECK_CUDA(cudaEventCreate(&start_event));
        CHECK_CUDA(cudaEventCreate(&stop_event));

        CHECK_CUDA(cudaEventRecord(start_event));

        // Launch measurement kernel with sufficient iterations for ~50ms runtime
        measure_kernel<<<1, 32>>>(d_start_clock, d_end_clock, d_dummy_output, 5000000);

        CHECK_CUDA(cudaEventRecord(stop_event));
        CHECK_CUDA(cudaEventSynchronize(stop_event));

        float elapsed_ms;
        CHECK_CUDA(cudaEventElapsedTime(&elapsed_ms, start_event, stop_event));

        // Copy clock values back
        unsigned long long start_clk, end_clk;
        CHECK_CUDA(cudaMemcpy(&start_clk, d_start_clock, sizeof(unsigned long long), cudaMemcpyDeviceToHost));
        CHECK_CUDA(cudaMemcpy(&end_clk, d_end_clock, sizeof(unsigned long long), cudaMemcpyDeviceToHost));

        unsigned long long clock_delta = end_clk - start_clk;

        // Calculate frequency in MHz
        float freq_mhz = static_cast<float>(clock_delta) / (elapsed_ms * 1000.0f);
        frequencies[i] = freq_mhz;

        CHECK_CUDA(cudaEventDestroy(start_event));
        CHECK_CUDA(cudaEventDestroy(stop_event));
    }

    // Calculate median frequency
    std::sort(frequencies.begin(), frequencies.end());
    float median_freq = frequencies[num_measurements / 2];

    // Cleanup
    CHECK_CUDA(cudaFree(d_start_clock));
    CHECK_CUDA(cudaFree(d_end_clock));
    CHECK_CUDA(cudaFree(d_dummy_output));

    printf("%.2f\n", median_freq);

    return 0;
}

