__global__ void bandwidth_kernel(float* input, float* output, int n) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;

    for (int i = tid; i < n; i += stride) {
        output[i] = input[i] * 2.0f + 1.0f;
    }
}

__global__ void warmup_kernel(float* data, int n) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;

    for (int i = tid; i < n; i += stride) {
        data[i] = data[i] * 1.0f + 1.0f;
    }
}

int main() {
    // Allocate 256MB of data (enough to bypass caches)
    const size_t size = 64 * 1024 * 1024; // 64M floats = 256MB
    const size_t bytes = size * sizeof(float);

    float *d_input, *d_output;
    CHECK_CUDA(cudaMalloc(&d_input, bytes));
    CHECK_CUDA(cudaMalloc(&d_output, bytes));

    // Initialize input data
    std::vector<float> h_data(size, 1.0f);
    CHECK_CUDA(cudaMemcpy(d_input, h_data.data(), bytes, cudaMemcpyHostToDevice));

    // Configure kernel launch parameters
    const int blockSize = 256;
    const int numBlocks = 64; // Use enough blocks to saturate memory

    // Warmup phase - run kernel to reach steady state
    cudaEvent_t start_warmup, stop_warmup;
    CHECK_CUDA(cudaEventCreate(&start_warmup));
    CHECK_CUDA(cudaEventCreate(&stop_warmup));

    CHECK_CUDA(cudaEventRecord(start_warmup));
    warmup_kernel<<<numBlocks, blockSize>>>(d_input, size);
    CHECK_CUDA(cudaDeviceSynchronize());
    CHECK_CUDA(cudaEventRecord(stop_warmup));
    CHECK_CUDA(cudaEventSynchronize(stop_warmup));

    // Measurement phase
    cudaEvent_t start_event, stop_event;
    CHECK_CUDA(cudaEventCreate(&start_event));
    CHECK_CUDA(cudaEventCreate(&stop_event));

    CHECK_CUDA(cudaEventRecord(start_event));
    bandwidth_kernel<<<numBlocks, blockSize>>>(d_input, d_output, size);
    CHECK_CUDA(cudaDeviceSynchronize());
    CHECK_CUDA(cudaEventRecord(stop_event));
    CHECK_CUDA(cudaEventSynchronize(stop_event));

    // Calculate elapsed time
    float elapsed_ms;
    CHECK_CUDA(cudaEventElapsedTime(&elapsed_ms, start_event, stop_event));
    float elapsed_s = elapsed_ms / 1000.0f;

    // Calculate bandwidth
    // We're reading 'size' floats and writing 'size' floats
    // Total bytes = 2 * size * sizeof(float)
    double total_bytes = 2.0 * size * sizeof(float);
    double bandwidth_gbps = total_bytes / (elapsed_s * 1e9);

    // Cleanup
    CHECK_CUDA(cudaFree(d_input));
    CHECK_CUDA(cudaFree(d_output));
    CHECK_CUDA(cudaEventDestroy(start_event));
    CHECK_CUDA(cudaEventDestroy(stop_event));
    CHECK_CUDA(cudaEventDestroy(start_warmup));
    CHECK_CUDA(cudaEventDestroy(stop_warmup));

    printf("%.2f\n", bandwidth_gbps);

    return 0;
}

