#include <cuda_runtime.h>
#include <iostream>
#include <vector>

#define WARMUP_ITERATIONS 3
#define MEASURE_ITERATIONS 10
#define SHARED_MEM_SIZE 49152  // 48KB per block (max shared mem per block)

__global__ void shared_bandwidth_kernel(int *dummy_output) {
    __shared__ float sdata[SHARED_MEM_SIZE / sizeof(float)];

    int tid = threadIdx.x;
    int bid = blockIdx.x;
    int block_size = blockDim.x;

    // Initialize shared memory
    for (int i = tid; i < SHARED_MEM_SIZE / sizeof(float); i += block_size) {
        sdata[i] = (float)(bid * block_size + tid);
    }
    __syncthreads();

    unsigned int start_cycle = clock();

    // Perform multiple rounds of shared memory accesses to maximize bandwidth
    const int rounds = 100;
    float temp = 0.0f;
    for (int r = 0; r < rounds; r++) {
        // Bank-conflict-free access pattern: each thread accesses different banks
        for (int i = tid; i < SHARED_MEM_SIZE / sizeof(float); i += block_size) {
            sdata[i] = sdata[i] + 1.0f;
            temp += sdata[i];
        }
        __syncthreads();

        // Another round of accesses
        for (int i = tid; i < SHARED_MEM_SIZE / sizeof(float); i += block_size) {
            sdata[i] = sdata[i] * 2.0f;
            temp += sdata[i];
        }
        __syncthreads();
    }

    unsigned int end_cycle = clock();

    // Write timing result to global memory to prevent optimization
    if (tid == 0) {
        dummy_output[bid] = end_cycle - start_cycle;
    }
}

int main() {
    const int num_blocks = 200;
    const int threads_per_block = 256;
    const size_t total_threads = num_blocks * threads_per_block;

    // Calculate total shared memory accessed
    const size_t bytes_per_thread = (SHARED_MEM_SIZE / threads_per_block);
    const size_t total_bytes_accessed = total_threads * bytes_per_thread * 2 * 100; // Read+Write * rounds

    // Allocate dummy output array to store timing info
    int *h_dummy_output = new int[num_blocks];
    int *d_dummy_output;
    cudaMalloc(&d_dummy_output, num_blocks * sizeof(int));

    // Warmup iterations
    for (int i = 0; i < WARMUP_ITERATIONS; i++) {
        shared_bandwidth_kernel<<<num_blocks, threads_per_block>>>(d_dummy_output);
    }
    cudaDeviceSynchronize();

    // Create CUDA events for timing
    cudaEvent_t start_event, stop_event;
    cudaEventCreate(&start_event);
    cudaEventCreate(&stop_event);

    // Measurement iterations
    cudaEventRecord(start_event);
    for (int i = 0; i < MEASURE_ITERATIONS; i++) {
        shared_bandwidth_kernel<<<num_blocks, threads_per_block>>>(d_dummy_output);
    }
    cudaEventRecord(stop_event);
    cudaEventSynchronize(stop_event);

    // Calculate elapsed time
    float elapsed_ms = 0;
    cudaEventElapsedTime(&elapsed_ms, start_event, stop_event);
    double elapsed_seconds = elapsed_ms / 1000.0;

    // Calculate bandwidth
    double bandwidth_gbps = (double(total_bytes_accessed) * MEASURE_ITERATIONS) / (elapsed_seconds * 1e9);

    // Cleanup
    cudaFree(d_dummy_output);
    delete[] h_dummy_output;
    cudaEventDestroy(start_event);
    cudaEventDestroy(stop_event);

    std::cout << bandwidth_gbps << std::endl;

    return 0;
}

