#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>

#define WARMUP_ITERATIONS 10
#define MEASURE_ITERATIONS 100
#define NODES_PER_KB 8  // 8 nodes per KB since each node is 128 bytes

__global__ void initRandomPermutation(int *indices, int n, unsigned long seed) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    // Simple linear congruential generator for device-side randomization
    unsigned long val = seed ^ idx;
    val = ((val >> 16) ^ val) * 0x45d9f3b;
    val = ((val >> 16) ^ val) * 0x45d9f3b;
    val = (val >> 16) ^ val;

    indices[idx] = val % n;
}

__global__ void resolveConflicts(int *indices, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    // Resolve conflicts by swapping duplicates
    for (int i = 0; i < n; i++) {
        if (indices[i] == idx && i != idx) {
            int temp = indices[idx];
            indices[idx] = indices[i];
            indices[i] = temp;
        }
    }
}

__global__ void createLinkedList(int *nodes, int *indices, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    // Each node points to the next one in the shuffled order
    int next_idx = (idx + 1) % n;
    nodes[indices[idx]] = indices[next_idx];
}

__global__ void flushCaches(int *nodes, int size) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid == 0) {
        // Touch all memory to evict from cache
        volatile int sum = 0;
        for (int i = 0; i < size; i += 32) {  // Step by cache line size
            sum += nodes[i];
        }
        // Write back to prevent optimization
        if (sum == 0) nodes[0] = sum;  // Never executed but prevents optimization
    }
}

__global__ void pointerChaseKernel(volatile int *nodes, int start_node, int num_steps, long long *result) {
    int idx = start_node;
    long long start_cycle = clock64();

    for (int i = 0; i < num_steps; i++) {
        idx = nodes[idx];
    }

    long long end_cycle = clock64();

    *result = end_cycle - start_cycle;
}

void shuffleArray(int *arr, int n) {
    for (int i = n - 1; i > 0; i--) {
        int j = rand() % (i + 1);
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}

int main() {
    const int dram_size = 64 * 1024 * NODES_PER_KB;  // 64MB array (enough nodes for 64MB at 128B per node)
    const int num_steps = 10000;

    int *h_indices = new int[dram_size];
    int *h_nodes = new int[dram_size];

    // Initialize indices array with sequential values
    for (int i = 0; i < dram_size; i++) {
        h_indices[i] = i;
    }

    // Shuffle the indices to randomize the linked list
    shuffleArray(h_indices, dram_size);

    // Create the linked list based on shuffled indices
    for (int i = 0; i < dram_size; i++) {
        int next_idx = (i + 1) % dram_size;
        h_nodes[h_indices[i]] = h_indices[next_idx];
    }

    int *d_nodes;
    int *d_indices;
    long long *d_result;

    cudaMalloc(&d_nodes, dram_size * sizeof(int));
    cudaMalloc(&d_indices, dram_size * sizeof(int));
    cudaMalloc(&d_result, sizeof(long long));

    cudaMemcpy(d_nodes, h_nodes, dram_size * sizeof(int), cudaMemcpyHostToDevice);
    cudaMemcpy(d_indices, h_indices, dram_size * sizeof(int), cudaMemcpyHostToDevice);

    // Warmup iterations
    for (int i = 0; i < WARMUP_ITERATIONS; i++) {
        pointerChaseKernel<<<1, 1>>>(d_nodes, 0, num_steps, d_result);
        cudaDeviceSynchronize();
    }

    // Flush caches
    flushCaches<<<1, 256>>>(d_nodes, dram_size);
    cudaDeviceSynchronize();

    long long total_cycles = 0;

    // Measurement iterations
    for (int i = 0; i < MEASURE_ITERATIONS; i++) {
        pointerChaseKernel<<<1, 1>>>(d_nodes, 0, num_steps, d_result);
        cudaDeviceSynchronize();

        long long cycles;
        cudaMemcpy(&cycles, d_result, sizeof(long long), cudaMemcpyDeviceToHost);
        total_cycles += cycles;
    }

    double avg_cycles_per_access = (double)total_cycles / (MEASURE_ITERATIONS * num_steps);

    printf("%.2f\n", avg_cycles_per_access);

    delete[] h_indices;
    delete[] h_nodes;

    cudaFree(d_nodes);
    cudaFree(d_indices);
    cudaFree(d_result);

    return 0;
}

