#include <device_launch_parameters.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>

#define WARMUP_ITERATIONS 10
#define MEASURE_ITERATIONS 50
#define CHASE_STEPS 10000

__global__ void initRandomPermutation(int *indices, int n, unsigned long seed) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
