__global__ void flushCaches(int *nodes, int size) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid == 0) {
        // Touch all memory to evict from cache
        volatile int sum = 0;
        for (int i = 0; i < size; i += 32) {  // Step by cache line size
            sum += nodes[i];
        }
        // Write back to prevent optimization
        if (sum == 0) nodes[0] = sum;  // Never executed but prevents optimization
    }
}

int main() {
    // Define the sizes to test in KB
    int sizes_kb[] = {128, 256, 512, 1024, 1536, 2048, 2560, 3072, 3584, 4096, 5120, 6144, 8192, 12288, 16384};
    int num_sizes = sizeof(sizes_kb) / sizeof(sizes_kb[0]);

    double latencies[15];

    for (int i = 0; i < num_sizes; i++) {
        int size_kb = sizes_kb[i];
        int size_ints = (size_kb * 1024) / sizeof(int);

        int *h_indices = new int[size_ints];
        int *h_nodes = new int[size_ints];

        // Initialize indices array with sequential values
        for (int j = 0; j < size_ints; j++) {
            h_indices[j] = j;
        }

        // Create the linked list based on shuffled indices
        for (int j = 0; j < size_ints; j++) {
            int next_idx = (j + 1) % size_ints;
            h_nodes[h_indices[j]] = h_indices[next_idx];
        }

        int *d_nodes;
        int *d_indices;
        long long *d_result;

        cudaMalloc(&d_nodes, size_ints * sizeof(int));
        cudaMalloc(&d_indices, size_ints * sizeof(int));
        cudaMalloc(&d_result, sizeof(long long));

        cudaMemcpy(d_nodes, h_nodes, size_ints * sizeof(int), cudaMemcpyHostToDevice);
        cudaMemcpy(d_indices, h_indices, size_ints * sizeof(int), cudaMemcpyHostToDevice);

        // Warmup iterations
        for (int w = 0; w < WARMUP_ITERATIONS; w++) {
            pointerChaseKernel<<<1, 1>>>(d_nodes, 0, CHASE_STEPS, d_result);
            cudaDeviceSynchronize();
        }

        // Flush caches
        flushCaches<<<1, 256>>>(d_nodes, size_ints);
        cudaDeviceSynchronize();

        long long total_cycles = 0;

        // Measurement iterations
        for (int m = 0; m < MEASURE_ITERATIONS; m++) {
            pointerChaseKernel<<<1, 1>>>(d_nodes, 0, CHASE_STEPS, d_result);
            cudaDeviceSynchronize();

            long long cycles;
            cudaMemcpy(&cycles, d_result, sizeof(long long), cudaMemcpyDeviceToHost);
            total_cycles += cycles;
        }

        double avg_cycles_per_access = (double)total_cycles / (MEASURE_ITERATIONS * CHASE_STEPS);
        latencies[i] = avg_cycles_per_access;

        delete[] h_indices;
        delete[] h_nodes;

        cudaFree(d_nodes);
        cudaFree(d_indices);
        cudaFree(d_result);
    }

    // Find the cliff point - where latency increases significantly
    int cliff_index = 0;
    double max_diff = 0.0;

    for (int i = 1; i < num_sizes; i++) {
        double diff = latencies[i] - latencies[i-1];
        if (diff > max_diff) {
            max_diff = diff;
            cliff_index = i;
        }
    }

    // Output the L2 cache size in KB
    printf("%d\n", sizes_kb[cliff_index]);

    return 0;
}

