#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <stdio.h>

#define WARP_SIZE 32
#define NUM_ITERATIONS 1000
#define SHARED_MEM_SIZE 1024

__global__ void conflict_free_kernel(volatile int* dummy_output) {
    __shared__ int smem[SHARED_MEM_SIZE];

    unsigned long long start_cycle = clock64();

    for (int iter = 0; iter < NUM_ITERATIONS; iter++) {
        // Each thread accesses its own unique bank (no conflicts)
        int idx = threadIdx.x;
        smem[idx] = threadIdx.x + iter;
        __syncthreads();

        // Read back from the same location
        volatile int val = smem[idx];
        if (val != threadIdx.x + iter) {
            // This is just to prevent optimization
            *dummy_output = val;
        }
        __syncthreads();
    }

    unsigned long long end_cycle = clock64();
    if (threadIdx.x == 0) {
        *dummy_output = (int)(end_cycle - start_cycle);
    }
}

__global__ void conflict_kernel(volatile int* dummy_output) {
    __shared__ int smem[SHARED_MEM_SIZE];

    unsigned long long start_cycle = clock64();

    for (int iter = 0; iter < NUM_ITERATIONS; iter++) {
        // All threads in warp access the same bank (every 32nd element)
        int idx = (threadIdx.x * 32) % SHARED_MEM_SIZE;
        smem[idx] = threadIdx.x + iter;
        __syncthreads();

        // Read back from the same conflicting locations
        volatile int val = smem[(threadIdx.x * 32) % SHARED_MEM_SIZE];
        if (val != threadIdx.x + iter) {
            // This is just to prevent optimization
            *dummy_output = val;
        }
        __syncthreads();
    }

    unsigned long long end_cycle = clock64();
    if (threadIdx.x == 0) {
        *dummy_output = (int)(end_cycle - start_cycle);
    }
}

int main() {
    volatile int *d_dummy_output;
    cudaMalloc((void**)&d_dummy_output, sizeof(int));

    // Warmup
    conflict_free_kernel<<<1, WARP_SIZE>>>(d_dummy_output);
    cudaDeviceSynchronize();

    // Measure conflict-free cycles
    int free_cycles_total = 0;
    for (int i = 0; i < 5; i++) {
        conflict_free_kernel<<<1, WARP_SIZE>>>(d_dummy_output);
        cudaDeviceSynchronize();
        int cycles;
        cudaMemcpy((void*)&cycles, (void*)d_dummy_output, sizeof(int), cudaMemcpyDeviceToHost);
        free_cycles_total += cycles;
    }
    float avg_free_cycles = (float)free_cycles_total / 5.0f;

    // Measure conflict cycles
    int conflict_cycles_total = 0;
    for (int i = 0; i < 5; i++) {
        conflict_kernel<<<1, WARP_SIZE>>>(d_dummy_output);
        cudaDeviceSynchronize();
        int cycles;
        cudaMemcpy((void*)&cycles, (void*)d_dummy_output, sizeof(int), cudaMemcpyDeviceToHost);
        conflict_cycles_total += cycles;
    }
    float avg_conflict_cycles = (float)conflict_cycles_total / 5.0f;

    // Calculate penalty per access
    int total_accesses = WARP_SIZE * NUM_ITERATIONS * 2; // 2 ops per iteration (read + write)
    float penalty_per_access = (avg_conflict_cycles - avg_free_cycles) / total_accesses;

    printf("%.2f\n", penalty_per_access);

    cudaFree((void*)d_dummy_output);
    return 0;
}
